import numpy as npimport cv2from matplotlib import pyplot as pltfrom scipy import ndimagefrom skimage import io, color, measure"""Step1:Read imageStep2: DenoisingStep3: Clean up imageStep4: Label grains in maskStep5: Measure properties of each grainStep6; Output results into a csv file"""img = cv2.imread("../data/grains2.jpg",0)pixels_to_um = 0.5 #1 pixel = 0.5 micrometers#Step2plt.hist(img.flat, bins = 100, range = (0, 255))ret, thresh = cv2.threshold(img, 0, 255, cv2.THRESH_BINARY+cv2.THRESH_OTSU)"""if pixel > threshold:    pixel = 255else:    pixel = 0"""#Step3 clean up the imagekernel = np.ones((3,3), np.uint)eroded = cv2.erode(thresh, kernel, iterations=1)dilated = cv2.dilate(eroded, kernel, iterations =1)plt.figure(figsize=(16,8))plt.subplot(1,2,1)plt.imshow(eroded, cmap = 'gray')plt.title("Erosion")plt.subplot(1,2,2)plt.imshow(dilated, cmap = 'gray')plt.title("Dilation")#Step4mask = dilated ==255s = [[1,1,1],[1,1,1],[1,1,1]]#Describes Which neighboring pixels count as connectedlabel_mask, num_labels = ndimage.label(mask, structure = s)#t scans the image and groups connected white pixels together.#Each connected region receives a unique integer label#label_mask: Image where each object has its own label number.#num_labels: Total number of connected objects.#Step 5clusters = measure.regionprops(label_mask, intensity_image=img)with open('image_measurement.csv', 'w') as output_file:    output_file.write(        'Label,Area_um2,EquivalentDiameter_um,Orientation_deg,'        'MajorAxisLength_um,MinorAxisLength_um,Perimeter_um,'        'MinIntensity,MeanIntensity,MaxIntensity\n'    )    for obj in clusters:        label = obj.label        area = obj.area * pixels_to_um**2        equiv_diameter = obj.equivalent_diameter * pixels_to_um        orientation = obj.orientation * 57.2958        major_axis = obj.major_axis_length * pixels_to_um        minor_axis = obj.minor_axis_length * pixels_to_um        perimeter = obj.perimeter * pixels_to_um        min_intensity = obj.min_intensity        mean_intensity = obj.mean_intensity        max_intensity = obj.max_intensity        output_file.write(            f'{label},{area},{equiv_diameter},{orientation},'            f'{major_axis},{minor_axis},{perimeter},'            f'{min_intensity},{mean_intensity},{max_intensity}\n'        )